def size_to_bytes(size: str) -> int:

    units = {
        'K': 1000,
        'M': 1000000,
        'G': 1000000000,
        'T': 1000000000000,
    }

    if size[-1].upper() in units:
        number = float(size[:-1])
        unit = size[-1].upper()
        return int(number * units[unit])
    else:
        return int(size)

